import{_ as a,o as r,c as d,a3 as e}from"./chunks/framework.BveOjhN0.js";const b=JSON.parse('{"title":"系统概述","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/overview.md","filePath":"cosmos/basic-app/overview.md","lastUpdated":1783773945000}'),i={name:"cosmos/basic-app/overview.md"};function o(n,t,l,h,s,c){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="系统概述" tabindex="-1">系统概述 <a class="header-anchor" href="#系统概述" aria-label="Permalink to &quot;系统概述&quot;">​</a></h1><p>XiHan.BasicApp 是一个<strong>企业级中后台内核</strong>：后端基于 .NET 10 与 <a href="./../framework/">XiHan.Framework</a>，前端基于 Vue 3。它把中后台系统里&quot;每个项目都要重做一遍&quot;的部分——身份、权限、租户、审计、代码生成、实时通信——一次性做好，让你专注在真正的业务上。</p><h2 id="定位" tabindex="-1">定位 <a class="header-anchor" href="#定位" aria-label="Permalink to &quot;定位&quot;">​</a></h2><ul><li><strong>可直接投产的中后台起点</strong>：完整的 RBAC + ABAC 权限、多租户、审计闭环，改改业务就能上线</li><li><strong>全栈实践参考</strong>：一套规范的 .NET + Vue 前后端分离工程，从契约到 UI 数据流都可借鉴</li><li><strong>框架用法样板</strong>：XiHan.Framework 各能力在真实业务里怎么用，这里有活的例子</li></ul><h2 id="架构风格" tabindex="-1">架构风格 <a class="header-anchor" href="#架构风格" aria-label="Permalink to &quot;架构风格&quot;">​</a></h2><p>系统采用<strong>前后端分离</strong>：</p><ul><li><strong>后端</strong>遵循 DDD 分层与 CQRS，应用服务经<strong>动态 API</strong> 直接暴露为 REST 接口——不写 Controller，接口即服务方法</li><li><strong>前端</strong>使用 Vue 3 + TypeScript + Naive UI，列表页由 <strong>Schema 驱动</strong>，搜索/表格/导出按配置生成，并对权限、租户、个人偏好三重感知</li></ul><p>详见 <a href="./architecture">系统架构</a>。</p><h2 id="能力全景" tabindex="-1">能力全景 <a class="header-anchor" href="#能力全景" aria-label="Permalink to &quot;能力全景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>领域</th><th>关键能力</th></tr></thead><tbody><tr><td><a href="./identity">身份与认证</a></td><td>用户/角色/部门/菜单；JWT 双令牌；账号密码、邮箱/短信验证码、OAuth2（GitHub/Google/QQ）、2FA</td></tr><tr><td><a href="./permissions">权限</a></td><td>RBAC + ABAC，权限码 <code>module:resource:action</code>（如 <code>saas:user:read</code>），数据范围，字段级脱敏，会话角色激活</td></tr><tr><td><a href="./multi-tenancy">多租户</a></td><td>字段级隔离，邮箱全局唯一登录，租户版本（Edition）权限白名单门控</td></tr><tr><td><a href="./messaging">消息中心</a></td><td>五类消息 + 优先级 + 强制阅读；模板；四渠道扇出；SignalR 通知与在线聊天</td></tr><tr><td><a href="./audit-log">审计日志</a></td><td>访问/API/操作/异常/登录/实体变更 六类日志，落库前自动脱敏</td></tr><tr><td><a href="./code-generation">代码生成</a></td><td>单表/树形/主从三模式，实体→DTO→API→前端页一键生成，Scriban 模板</td></tr><tr><td><a href="./ai">AI 能力</a></td><td>Provider 库化管理（热切换）、RAG 知识库（Qdrant）、Agent / MCP</td></tr><tr><td>平台能力</td><td>动态 API、菜单单一事实源、分布式缓存、网关灰度、消息模板、SignalR 实时</td></tr><tr><td><a href="./frontend">前端体验</a></td><td>Schema 驱动列表、命令面板、多标签、消息中心、偏好中心、富文本、时区切换</td></tr></tbody></table><p>完整清单见 <a href="./features">功能清单</a>。</p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><h3 id="后端" tabindex="-1">后端 <a class="header-anchor" href="#后端" aria-label="Permalink to &quot;后端&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技术</th><th>说明</th></tr></thead><tbody><tr><td>.NET 10 / C#</td><td>运行时与语言</td></tr><tr><td>XiHan.Framework 3.5.0</td><td>自研模块化应用框架</td></tr><tr><td>SqlSugar</td><td>ORM，支持 PostgreSQL / MySQL / MariaDB</td></tr><tr><td>Redis</td><td>分布式缓存与分布式锁</td></tr><tr><td>SignalR</td><td>实时通信</td></tr><tr><td>Serilog</td><td>结构化日志</td></tr><tr><td>Scalar</td><td>API 文档</td></tr></tbody></table><h3 id="前端" tabindex="-1">前端 <a class="header-anchor" href="#前端" aria-label="Permalink to &quot;前端&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技术</th><th>说明</th></tr></thead><tbody><tr><td>Vue 3.5+</td><td>UI 框架</td></tr><tr><td>TypeScript 5.9+</td><td>类型系统</td></tr><tr><td>Vite 6</td><td>构建工具</td></tr><tr><td>Naive UI</td><td>组件库</td></tr><tr><td>Pinia</td><td>状态管理</td></tr><tr><td>Tailwind CSS 4</td><td>原子化 CSS</td></tr><tr><td>Tiptap</td><td>富文本编辑器</td></tr><tr><td>vue-i18n</td><td>国际化</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./getting-started">快速开始</a>：在本地把系统跑起来</li><li><a href="./architecture">系统架构</a>：理解后端模块与前后端协作</li><li><a href="./permissions">权限模型</a>：RBAC + ABAC 与多租户隔离</li></ul>',18)])])}const p=a(i,[["render",o]]);export{b as __pageData,p as default};
